--
-- Name: upload_sessions; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.upload_sessions (
    id character varying(64) NOT NULL,
    user_id character varying(64) NOT NULL,
    project_id character varying(128) NOT NULL,
    status character varying(32) NOT NULL,
    bucket character varying(256) NOT NULL,
    object_key character varying(1024) NOT NULL,
    filename character varying(512) NOT NULL,
    size_bytes bigint NOT NULL,
    content_type character varying(256),
    expires_at timestamp with time zone NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    upload_mode character varying(32) DEFAULT 'single_file'::character varying NOT NULL,
    items_json text,
    manifest_json text,
    expected_count integer,
    expected_total_size bigint,
    root_dir_name character varying(512),
    asset_name character varying(512),
    result_payload_json text
);


--
-- Name: COLUMN upload_sessions.id; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.upload_sessions.id IS 'upload_session_id（UUID hex 等）';


--
-- Name: COLUMN upload_sessions.status; Type: COMMENT; Schema: public; Owner: -
--

COMMENT ON COLUMN public.upload_sessions.status IS 'presigned|completed|failed|expired';


--
-- Name: user_models; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.user_models (
    id integer NOT NULL,
    user_id integer NOT NULL,
    provider_id integer NOT NULL,
    model_id integer NOT NULL,
    custom_name text,
    is_enabled integer DEFAULT 1,
    parameters text,
    sort_order integer DEFAULT 0,
    created_at text DEFAULT CURRENT_TIMESTAMP,
    updated_at text DEFAULT CURRENT_TIMESTAMP,
    project_id character varying
);


